static void CloseHotkeyDialog(bool applyChanges){
    if(!hotkeyWindow)return;if(applyChanges&&hotkeyDialogIndex>=0)hotkeys[static_cast<size_t>(hotkeyDialogIndex)].bindings=hotkeyDialogBindings;HWND dialog=hotkeyWindow,owner=mainWindow;hotkeyInitialFocusPending=false;if(owner&&IsWindow(owner))EnableWindow(owner,TRUE);DestroyWindow(dialog);if(owner&&IsWindow(owner)){if(applyChanges)RefreshSimpleCommands();if(GetAncestor(GetForegroundWindow(),GA_ROOT)!=owner)SetForegroundWindow(owner);SetActiveWindow(owner);SetFocus(commandList);}
}
